<?php
declare(strict_types=1);require_once __DIR__.'/comunicacion_centro.php';require_once __DIR__.'/permissions.php';exigirAutenticacion();
function contextoComunicacionAtenea():string{$rol=(string)$_SESSION['usuario_rol'];if($rol!=='administracion_docente')return$rol;$modo=modoHibridoActualAtenea();if($modo==='admin'){exigirPermiso('communications.view');return'admin';}exigirModoHibridoAtenea('docente');exigirPermiso('academic.communications.send');return'docente';}
function comunicacionCabecera(string $titulo,string $seccion,string $descripcion=''):array{if($seccion==='chat')$GLOBALS['atenea_layout_styles'][]='src/comunicaciones/assets/chat-modern.css';$rol=contextoComunicacionAtenea();if($rol==='admin'){require_once ATENEA_ROOT.'/src/dashboard/includes/cms.php';cmsCabecera($titulo,'comunicaciones/centro.php',$descripcion);return obtenerUsuarioActual()??[];}if($rol==='docente'){require_once ATENEA_ROOT.'/src/docente/_layout.php';docenteCabecera($titulo,'mensajes',$descripcion);return $GLOBALS['docentePortal']??[];}require_once __DIR__.'/portal_estudiante_layout.php';$p=portalEstudianteCabecera($titulo,'comunicaciones',$descripcion);return$p['perfil'];}
function comunicacionPie():void{$rol=contextoComunicacionAtenea();if($rol==='admin')cmsPie();elseif($rol==='docente')docentePie();else portalEstudiantePie();}
function comunicacionNav(string $activo):void{$items=['agenda'=>'Agenda','chat'=>'Chat','entrada'=>'Bandeja de entrada','enviados'=>'Enviados','redactar'=>'Redactar','no-leidos'=>'No leídos'];?><ul class="nav nav-pills flex-wrap gap-2 mb-4"><?php foreach($items as$k=>$v):?><li class="nav-item"><a class="nav-link <?=$activo===$k?'active':''?>" href="<?=atenea_url('src/comunicaciones/'.($k==='agenda'?'agenda.php':($k==='chat'?'chat.php':($k==='redactar'?'redactar.php':'correo.php?vista='.$k))))?>"><?=atenea_e($v)?></a></li><?php endforeach;?></ul><?php }
